    const n = words.length;
    if (n === 1) {
        return [0];
    }

    function commonPrefixLength(a: string, b: string): number {
        let i = 0;
        while (i < a.length && i < b.length) {
            if (a[i] !== b[i]) break;
            i++;
        }
        return i;
    }

    const pairs = new Array(n - 1);
    for (let i = 0; i < n - 1; i++) {
        pairs[i] = commonPrefixLength(words[i], words[i + 1]);
