    const prefixMax = new Array(n - 1);
    prefixMax[0] = pairs[0];
    for (let i = 1; i < n - 1; i++) {
        prefixMax[i] = Math.max(prefixMax[i - 1], pairs[i]);
    }

    const suffixMax = new Array(n - 1);
    suffixMax[n - 2] = pairs[n - 2];
    for (let i = n - 3; i >= 0; i--) {
        suffixMax[i] = Math.max(suffixMax[i + 1], pairs[i]);
    }

    const ans = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let candidate = 0;
        if (i >= 2) {
            candidate = Math.max(candidate, prefixMax[i - 2]);
        }
        if (i >= 1 && i < n - 1) {
            const newPair = commonPrefixLength(words[i - 1], words[i + 1]);
            candidate = Math.max(candidate, newPair);
        }
        if (i <= n - 3) {
            candidate = Math.max(candidate, suffixMax[i + 1]);
        }
        ans[i] = candidate;
    }

    return ans;
}
